package com.hospital.management.controller.admission;import com.hospital.management.service.*;import com.hospital.management.service.impl.RoomServiceImpl;import javax.servlet.annotation.WebServlet;import javax.servlet.http.*;import java.io.*;@WebServlet("/admin/rooms/status")public class RoomStatusServlet extends HttpServlet{private final RoomService s;public RoomStatusServlet(){this(new RoomServiceImpl());}RoomStatusServlet(RoomService s){this.s=s;}protected void doGet(HttpServletRequest q,HttpServletResponse r)throws IOException{r.sendError(405);}protected void doPost(HttpServletRequest q,HttpServletResponse r)throws IOException{Long id=AdmissionRequest.id(q.getParameter("roomId"));if(id==null){r.sendError(400);return;}s.updateRoomStatus(id,q.getParameter("action"),AdmissionRequest.audit(q));r.sendRedirect(q.getContextPath()+"/admin/rooms/view?id="+id);}}
